features.snippet:
module sub2(input clk, input rst, input d, output reg q);
  always @(posedge clk) if (rst) q <= 0; else q <= d;
endmodule
module sub1(input d, output q);
  sub2 sub2(.d(d), .q(q));
endmodule
module top(input clk, input rst, input d, output q);
  sub1 sub1(.d(d), .q(q));
  assign sub1.sub2.clk = clk;
  assign sub1.sub2.rst = rst;
endmodule
